const fs = require\('fs'\);
// Minimal 1x1 gray PNG then we'll use a proper one
// Actually let's create a minimal valid PNG with a solid color
// Using raw PNG generation
const width = 400, height = 300;
const color = [0xF2, 0xF2, 0xF7]; // #F2F2F7

function crc32\(buf\) {
  let c, n;
  const table = [];
  for \(n = 0; n < 256; n++\) {
    c = n;
    for \(let k = 0; k < 8; k++\) c = \(c & 1\) ? \(0xEDB88320 ^ \(c >>> 1\)\) : \(c >>> 1\);
    table[n] = c;
  }
  c = 0xFFFFFFFF;
  for \(let i = 0; i < buf.length; i++\) c = table[\(c ^ buf[i]\) & 0xFF] ^ \(c >>> 8\);
  return \(c ^ 0xFFFFFFFF\) >>> 0;
}

function chunk\(type, data\) {
  const len = Buffer.alloc\(4\);
  len.writeUInt32BE\(data.length\);
  const typeAndData = Buffer.concat\([Buffer.from\(type\), data]\);
  const crc = Buffer.alloc\(4\);
  crc.writeUInt32BE\(crc32\(typeAndData\)\);
  return Buffer.concat\([len, typeAndData, crc]\);
}

const zlib = require\('zlib'\);
const sig = Buffer.from\([137, 80, 78, 71, 13, 10, 26, 10]\);
const ihdr = Buffer.alloc\(13\);
ihdr.writeUInt32BE\(width, 0\);
ihdr.writeUInt32BE\(height, 4\);
ihdr[8] = 8; // bit depth
ihdr[9] = 2; // RGB
const raw = Buffer.alloc\(height * \(1 + width * 3\)\);
for \(let y = 0; y < height; y++\) {
  const offset = y * \(1 + width * 3\);
  raw[offset] = 0; // filter none
  for \(let x = 0; x < width; x++\) {
    raw[offset + 1 + x*3] = color[0];
    raw[offset + 2 + x*3] = color[1];
    raw[offset + 3 + x*3] = color[2];
  }
}
const compressed = zlib.deflateSync\(raw\);
const iend = Buffer.alloc\(0\);
const png = Buffer.concat\([sig, chunk\('IHDR', ihdr\), chunk\('IDAT', compressed\), chunk\('IEND', iend\)]\);
fs.writeFileSync\('/home/ubuntu/code_realmeet/assets/images/placeholder-activity.png', png\);
console.log\('Created', png.length, 'bytes'\);
")
